import{_ as a,o as i,c as r,ag as e}from"./chunks/framework.-Wrcbzkw.js";const u=JSON.parse('{"title":"LLM 技能（Skill）","description":"","frontmatter":{},"headers":[],"relativePath":"LLM/基础知识/skill.md","filePath":"LLM/基础知识/skill.md","lastUpdated":1778838236000}'),t={name:"LLM/基础知识/skill.md"};function o(s,l,n,h,d,k){return i(),r("div",null,[...l[0]||(l[0]=[e('<h1 id="llm-技能-skill" tabindex="-1">LLM 技能（Skill） <a class="header-anchor" href="#llm-技能-skill" aria-label="Permalink to &quot;LLM 技能（Skill）&quot;">​</a></h1><h2 id="什么是-llm-skill" tabindex="-1">什么是 LLM Skill <a class="header-anchor" href="#什么是-llm-skill" aria-label="Permalink to &quot;什么是 LLM Skill&quot;">​</a></h2><p>Skill 是指大语言模型通过训练或微调获得的特定能力或功能。</p><h2 id="skill-的分类" tabindex="-1">Skill 的分类 <a class="header-anchor" href="#skill-的分类" aria-label="Permalink to &quot;Skill 的分类&quot;">​</a></h2><h3 id="基础技能" tabindex="-1">基础技能 <a class="header-anchor" href="#基础技能" aria-label="Permalink to &quot;基础技能&quot;">​</a></h3><ol><li><strong>语言理解</strong>：理解自然语言的含义和意图</li><li><strong>文本生成</strong>：生成符合语法和语义的文本</li><li><strong>知识问答</strong>：回答关于各种主题的问题</li><li><strong>多语言支持</strong>：支持多种语言的理解和生成</li></ol><h3 id="高级技能" tabindex="-1">高级技能 <a class="header-anchor" href="#高级技能" aria-label="Permalink to &quot;高级技能&quot;">​</a></h3><ol><li><strong>代码生成</strong>：根据需求生成代码</li><li><strong>逻辑推理</strong>：进行复杂的逻辑推理</li><li><strong>数学计算</strong>：解决数学问题</li><li><strong>创意写作</strong>：创作诗歌、故事等</li></ol><h3 id="专业技能" tabindex="-1">专业技能 <a class="header-anchor" href="#专业技能" aria-label="Permalink to &quot;专业技能&quot;">​</a></h3><ol><li><strong>数据分析</strong>：分析和解释数据</li><li><strong>法律分析</strong>：解读法律条文和案例</li><li><strong>医疗诊断</strong>：提供医疗建议</li><li><strong>金融分析</strong>：分析金融市场和投资</li></ol><h2 id="skill-的获取方式" tabindex="-1">Skill 的获取方式 <a class="header-anchor" href="#skill-的获取方式" aria-label="Permalink to &quot;Skill 的获取方式&quot;">​</a></h2><h3 id="预训练" tabindex="-1">预训练 <a class="header-anchor" href="#预训练" aria-label="Permalink to &quot;预训练&quot;">​</a></h3><p>通过大规模数据集训练获得通用技能。</p><h3 id="微调" tabindex="-1">微调 <a class="header-anchor" href="#微调" aria-label="Permalink to &quot;微调&quot;">​</a></h3><p>在特定领域数据集上进行微调，获得专业技能。</p><h3 id="提示工程" tabindex="-1">提示工程 <a class="header-anchor" href="#提示工程" aria-label="Permalink to &quot;提示工程&quot;">​</a></h3><p>通过精心设计的提示词引导模型表现出特定技能。</p><h3 id="工具增强" tabindex="-1">工具增强 <a class="header-anchor" href="#工具增强" aria-label="Permalink to &quot;工具增强&quot;">​</a></h3><p>通过调用外部工具来扩展模型的技能范围。</p><h2 id="skill-评估" tabindex="-1">Skill 评估 <a class="header-anchor" href="#skill-评估" aria-label="Permalink to &quot;Skill 评估&quot;">​</a></h2><p>评估模型技能的方法包括：</p><ul><li>准确率测试</li><li>人工评估</li><li>基准数据集测试</li><li>实际应用反馈</li></ul><h2 id="skill-的局限性" tabindex="-1">Skill 的局限性 <a class="header-anchor" href="#skill-的局限性" aria-label="Permalink to &quot;Skill 的局限性&quot;">​</a></h2><ul><li>幻觉问题：可能生成错误信息</li><li>知识截止：训练数据有时效性</li><li>上下文限制：有限的上下文窗口</li><li>偏见问题：可能存在偏见和歧视</li></ul>',24)])])}const b=a(t,[["render",o]]);export{u as __pageData,b as default};
